<script setup lang="ts">
import { computed,onBeforeUnmount,onMounted,ref } from 'vue'
import { useRoute,useRouter } from 'vue-router'
import { ElMessage } from 'element-plus'
import { ArrowLeft,Connection,Refresh } from '@element-plus/icons-vue'
import { getDocument,getKnowledgeResult,getKnowledgeStatus,startKnowledgeExtraction,type GeologicalDocument,type GeologicalEntity,type KnowledgeResult,type KnowledgeStatus } from '@/api/documents'
const route=useRoute(),router=useRouter(),documentId=Number(route.params.id)
const loading=ref(true),starting=ref(false),document=ref<GeologicalDocument>(),status=ref<KnowledgeStatus>(),result=ref<KnowledgeResult>({entities:[],attributes:[],relations:[]}),provider=ref<'deepseek'|'qwen'>('deepseek'),tab=ref<'relations'|'attributes'|'terms'>('relations')
let timer:number|undefined
const entityMap=computed(()=>new Map(result.value.entities.map(e=>[e.id,e])))
const isExtracting=computed(()=>status.value?.status==='EXTRACTING')
const statusLabel=computed(()=>({PENDING:'等待抽取',EXTRACTING:'知识抽取中',COMPLETED:'抽取完成',FAILED:'抽取失败'}[status.value?.status||'PENDING']))
const relationLabels:Record<string,string>={LOCATED_IN:'位于',OCCURS_IN:'赋存于',INTRUDES:'侵入',CONTACTS:'接触',CONTROLS:'控制',CONTAINS:'包含'}
const attributeLabels:Record<string,string>={AGE:'年代',THICKNESS:'厚度',SCALE:'规模',GRADE:'品位',LITHOLOGY:'岩性'}
const normalizationLabels:Record<string,string>={EXACT:'标准名',ALIAS:'别名匹配',UNMATCHED:'未匹配',PENDING:'待处理'}
async function initialize(){if(!Number.isInteger(documentId)||documentId<=0)return router.replace('/knowledge');loading.value=true;try{const[d,s]=await Promise.all([getDocument(documentId),getKnowledgeStatus(documentId)]);document.value=d;status.value=s;if(s.status==='COMPLETED')result.value=await getKnowledgeResult(documentId);if(s.status==='EXTRACTING')schedule()}catch(e){ElMessage.error(message(e))}finally{loading.value=false}}
async function start(){starting.value=true;try{status.value=await startKnowledgeExtraction(documentId,provider.value);result.value={entities:[],attributes:[],relations:[]};ElMessage.success('属性关系抽取任务已提交');schedule()}catch(e){ElMessage.error(message(e))}finally{starting.value=false}}
function schedule(){if(timer)clearTimeout(timer);timer=window.setTimeout(poll,1600)}
async function poll(){try{const latest=await getKnowledgeStatus(documentId);status.value=latest;if(latest.status==='EXTRACTING')return schedule();if(latest.status==='COMPLETED'){result.value=await getKnowledgeResult(documentId);ElMessage.success(`抽取完成：${latest.attributeCount} 个属性，${latest.relationCount} 条关系`)}}catch(e){ElMessage.error(message(e))}}
function entity(id:number):GeologicalEntity|undefined{return entityMap.value.get(id)}
function message(e:unknown){return e instanceof Error?e.message:'操作失败'}
onMounted(initialize);onBeforeUnmount(()=>{if(timer)clearTimeout(timer)})
</script>
<template><div class="knowledge-page" v-loading="loading"><header class="entity-header"><button class="back-action" type="button" @click="router.push('/knowledge')"><el-icon><ArrowLeft/></el-icon>返回知识任务</button><div><span class="eyebrow">Phase 5 · Attributes & relations</span><h1>{{document?.name||'知识抽取'}}</h1><p>属性、关系与标准术语的证据化核查</p></div><div class="entity-run-controls"><div class="provider-switch"><button type="button" :class="{active:provider==='deepseek'}" @click="provider='deepseek'">DeepSeek</button><button type="button" :class="{active:provider==='qwen'}" @click="provider='qwen'">Qwen</button></div><button class="run-entity-button" type="button" :disabled="isExtracting||starting" @click="start"><el-icon><Refresh v-if="status?.status==='COMPLETED'||status?.status==='FAILED'"/><Connection v-else/></el-icon>{{status?.status==='COMPLETED'?'重新抽取':status?.status==='FAILED'?'重试抽取':'开始抽取'}}</button></div></header><section class="knowledge-status"><div><small>任务状态</small><strong :class="`is-${status?.status?.toLowerCase()}`">{{statusLabel}}</strong></div><el-progress :percentage="status?.progress||0" :stroke-width="6" :status="status?.status==='FAILED'?'exception':status?.status==='COMPLETED'?'success':undefined"/><div class="knowledge-metrics"><span><b>{{status?.attributeCount||0}}</b>属性</span><span><b>{{status?.relationCount||0}}</b>关系</span><span><b>{{status?.normalizedCount||0}}</b>标准化</span></div></section><div v-if="status?.errorMessage" class="parse-error"><strong>抽取异常</strong><p>{{status.errorMessage}}</p><button type="button" @click="start">重新尝试</button></div><nav class="knowledge-tabs" aria-label="知识结果类型"><button type="button" :class="{active:tab==='relations'}" @click="tab='relations'">关系网络 <small>{{result.relations.length}}</small></button><button type="button" :class="{active:tab==='attributes'}" @click="tab='attributes'">实体属性 <small>{{result.attributes.length}}</small></button><button type="button" :class="{active:tab==='terms'}" @click="tab='terms'">术语标准化 <small>{{result.entities.length}}</small></button></nav><section class="knowledge-results"><div v-if="tab==='relations'" class="relation-list"><article v-for="relation in result.relations" :key="relation.id"><div class="relation-route"><span><small>{{entity(relation.sourceEntityId)?.entityType}}</small><strong>{{entity(relation.sourceEntityId)?.standardName||entity(relation.sourceEntityId)?.entityName}}</strong></span><b>{{relationLabels[relation.relationType]}}</b><span><small>{{entity(relation.targetEntityId)?.entityType}}</small><strong>{{entity(relation.targetEntityId)?.standardName||entity(relation.targetEntityId)?.entityName}}</strong></span></div><footer><blockquote>{{relation.sourceText}}</blockquote><span>第 {{relation.page}} 页 · {{Math.round(relation.confidence*100)}}%</span></footer></article></div><div v-else-if="tab==='attributes'" class="attribute-grid"><article v-for="attribute in result.attributes" :key="attribute.id"><header><span>{{attributeLabels[attribute.attributeType]}}</span><b>{{Math.round(attribute.confidence*100)}}%</b></header><h3>{{entity(attribute.entityId)?.standardName||entity(attribute.entityId)?.entityName}}</h3><strong>{{attribute.originalValue}}</strong><p>{{attribute.sourceText}}</p><small>第 {{attribute.page}} 页</small></article></div><div v-else class="term-table"><header><span>原名称</span><span>标准名称</span><span>实体类型</span><span>匹配结果</span></header><div v-for="item in result.entities" :key="item.id"><strong>{{item.entityName}}</strong><span>{{item.standardName||item.entityName}}</span><span>{{item.entityType}}</span><b :class="`match-${(item.normalizationStatus||'PENDING').toLowerCase()}`">{{normalizationLabels[item.normalizationStatus||'PENDING']}}</b></div></div><div v-if="status?.status!=='COMPLETED'&&!isExtracting" class="empty-parsing"><Connection/><strong>尚未生成知识结果</strong><p>选择模型并启动属性关系抽取。</p></div></section></div></template>
